const data = $input.first().json;
const errors = [];
if (!data.video_url) errors.push('video_url is required');
if (!data.title) errors.push('title is required');
if (!data.source_id) errors.push('source_id is required');
if (data.video_url && !String(data.video_url).startsWith('http')) errors.push('video_url must be absolute URL');
if (errors.length) throw new Error(`Invalid video data: ${errors.join(', ')}`);
return [{ json: data }];

const data = $input.first().json;
const tags = Array.isArray(data.hashtags)
  ? data.hashtags.map(t => String(t).startsWith('#') ? t : `#${t}`).join(' ')
  : '#BongBanViet #TableTennis #BongBan';
const caption = [
  data.product_name ? `${data.product_name}: điểm nổi bật cần biết?` : data.title,
  data.description || 'Gợi ý nhanh cho người chơi bóng bàn phong trào.',
  'Xem hết video và nhắn tin nếu bạn cần tư vấn setup.',
  tags
].filter(Boolean).join('\n');
return [{ json: { ...data, caption } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;

const tags = Array.isArray(data.hashtags)
  ? data.hashtags.map(t => String(t).startsWith('#') ? t : `#${t}`).join(' ')
  : '#BongBanViet #TableTennis #BongBan';
const fullCaption = [data.caption, tags].filter((v, i, a) => a.indexOf(v) === i).join('\n').replace(/\n{2,}/g, '\n');

const sourceId = String(data.source_id || 'unknown');
const date = new Date().toISOString().slice(0, 10);
const safeId = sourceId.replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 40);
const basename = `tiktok-${date}-${safeId}`;
const outputDir = path.join(process.cwd(), 'output');
fs.mkdirSync(outputDir, { recursive: true });

const steps = [
  '1. Tải video từ link video_url về máy',
  '2. Mở app TikTok → nhấn dấu + để tạo video mới',
  '3. Chọn "Tải lên" và chọn video vừa tải',
  '4. Dán nội dung caption vào ô mô tả',
  '5. Quyền xem: Công khai (Public to Everyone)',
  '6. Bật Duet / Bình luận / Stitch',
  '7. Thêm nhạc nền nếu cần',
  '8. Nhấn Đăng'
];

const jsonData = {
  channel: 'tiktok',
  generated_at: new Date().toISOString(),
  source_id: sourceId,
  video_url: data.video_url,
  caption: fullCaption,
  post_info: { privacy_level: 'PUBLIC_TO_EVERYONE', disable_duet: false, disable_comment: false, disable_stitch: false },
  manual_steps: steps
};

const md = [
  `# TikTok Draft — ${date}`,
  '',
  '## Thông tin video',
  '',
  `- **Source ID:** \`${sourceId}\``,
  `- **Sản phẩm:** ${data.product_name || data.title || '—'}`,
  `- **Video URL:** ${data.video_url}`,
  `- **Tạo lúc:** ${new Date().toLocaleString('vi-VN')}`,
  '',
  '## Caption (copy nguyên vào TikTok)',
  '',
  '```',
  fullCaption,
  '```',
  '',
  '## Cài đặt',
  '',
  '- Quyền xem: **Công khai**',
  '- Duet / Bình luận / Stitch: **Bật**',
  '',
  '## Các bước đăng thủ công',
  '',
  steps.join('\n')
].join('\n');

fs.writeFileSync(path.join(outputDir, `${basename}.json`), JSON.stringify(jsonData, null, 2));
fs.writeFileSync(path.join(outputDir, `${basename}.md`), md);

return [{ json: { channel: 'tiktok', mode: 'draft', source_id: sourceId, json_file: `output/${basename}.json`, md_file: `output/${basename}.md`, caption: fullCaption, generated_at: jsonData.generated_at } }];

const result = $input.first().json;
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
if (webhook) {
  const res = await fetch(webhook, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(result)
  });
  if (!res.ok) console.warn('Result webhook failed', res.status);
}
return [{ json: { ...result, notified: !!webhook, saved_at: new Date().toISOString() } }];

const error = $execution.error || {};
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
const payload = { channel: 'tiktok', ok: false, error: error.message || 'Unknown error', time: new Date().toISOString() };
if (webhook) {
  await fetch(webhook, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }).catch(() => {});
}
return [{ json: payload }];
